using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTool
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to query (e.g. \"users/1\")")] string path,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

